import{j as s,b as i,c as a,aa as l}from"./chunks/framework.Bxf40uRC.js";const E=JSON.parse('{"title":"锁","description":"","frontmatter":{},"headers":[],"relativePath":"Mysql/锁.md","filePath":"Mysql/锁.md","lastUpdated":null}'),t={name:"Mysql/锁.md"},e=l(`<h1 id="锁" tabindex="-1">锁 <a class="header-anchor" href="#锁" aria-label="Permalink to &quot;锁&quot;">​</a></h1><h2 id="什么sql语句会加行级锁" tabindex="-1">什么SQL语句会加行级锁？ <a class="header-anchor" href="#什么sql语句会加行级锁" aria-label="Permalink to &quot;什么SQL语句会加行级锁？&quot;">​</a></h2><p>普通的select语句是不会对记录进行加锁的(除了串行化隔离级别)，因为它属于快照读，通过MVCC实现的</p><p>如果要在查询的时候对记录加行级锁，可以使用下面这两种方式，这两种查询会加锁的语句成为<strong>锁定读</strong></p><div class="language-sql vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">sql</span><pre class="shiki shiki-themes github-light github-dark vp-code"><code><span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">//</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> 对读取的记录加共享锁(S型锁)</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">select</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> ... lock </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">in</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> share mode;</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">//</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> 对读取的记录加独占锁(X型锁)</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">select</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> ... </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">for</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> update</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">;</span></span></code></pre></div><p>除了上面这两条锁定读语句会加行级锁之外，update和delete操作都会加行级锁，且锁的类型都是独占锁(X型锁)；</p><div class="language-sql vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">sql</span><pre class="shiki shiki-themes github-light github-dark vp-code"><code><span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">//</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">对操作的记录加独占锁(X型锁)</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">update</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> table</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> .... </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">where</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> id </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 1</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">;</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">//</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">对操作的记录加独占锁(X型锁)</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">delete</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> from</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> table</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> where</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> id </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 1</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">;</span></span></code></pre></div><p><img src="https://s2.loli.net/2024/04/16/sUJa5VpWXZjlYMb.png" alt="img"></p><h2 id="行级锁的种类" tabindex="-1">行级锁的种类 <a class="header-anchor" href="#行级锁的种类" aria-label="Permalink to &quot;行级锁的种类&quot;">​</a></h2><p><strong>不同的隔离级别下，行级锁的种类是不同的。</strong></p><p><strong>在读已提交隔离级别下，行级锁的种类只有记录锁，也就是仅仅把一条记录锁上；</strong></p><p>在<strong>可重复读隔离级别</strong>下，行级锁除了有记录锁，还有间隙锁(目的是避免幻读)，所以行级锁的种类主要有三类:</p><ul><li>Record Lock，记录锁，也就是把一条记录锁上；</li><li>Gap Lock，间隙锁，锁定一个范围，但是不包含记录本身；</li><li>Next-key Lock： Record Lock + Gap Lock的组合，锁定一个范围，并且锁定记录本身</li></ul><h3 id="record-lock" tabindex="-1">Record Lock <a class="header-anchor" href="#record-lock" aria-label="Permalink to &quot;Record Lock&quot;">​</a></h3><div class="language-sql vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">sql</span><pre class="shiki shiki-themes github-light github-dark vp-code"><code><span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">begin</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">;</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">select</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> *</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> from</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> t_test </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">where</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> id </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 1</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> for</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> update</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">;</span></span></code></pre></div><p>事务会对id=1的记录上一把X型锁(行级独占锁)，其他事务如果想进行更新和删除都是会被阻塞的；如果其他事务想插入一条数据，那么不会被阻塞，而是报主键冲突的错误(因为主键有唯一性约束)；</p><p>当事务commit之后，事务过程中生成的锁都会被释放；</p><h3 id="gap-lock" tabindex="-1">Gap Lock <a class="header-anchor" href="#gap-lock" aria-label="Permalink to &quot;Gap Lock&quot;">​</a></h3><p>间隙锁，只存在可重复读隔离级别，目的是为了解决可重复读隔离级别下的幻读现象；</p><p>假设，表中有一个范围 id 为（3，5）间隙锁，那么其他事务就无法插入 id = 4 这条记录了，这样就有效的防止幻读现象的发生。</p><p><img src="https://s2.loli.net/2024/04/16/vmajTntiHwJ8QF4.png" alt="img"></p><p><strong>tip:</strong> 间隙锁虽然存在X型间隙锁和S型间隙锁，但是没有什么区别，间隙锁之间是兼容的，即两个事务可以同时持有包含共同间隙范围的间隙锁，并不存在互斥关系，因为间隙锁的目的是为了防止插入幻读记录而提出的；</p><h3 id="next-key-lock" tabindex="-1">Next-key Lock <a class="header-anchor" href="#next-key-lock" aria-label="Permalink to &quot;Next-key Lock&quot;">​</a></h3><p>Next-Key Lock 称为临键锁，是 Record Lock + Gap Lock 的组合，锁定一个范围，并且锁定记录本身。</p><p>假设，表中有一个范围 id 为（3，5] 的 next-key lock，那么其他事务即不能插入 id = 4 记录，也不能修改和删除 id = 5 这条记录。</p><p><img src="https://s2.loli.net/2024/04/16/v1cSoZPMNpF4Xhd.png" alt="img"></p><p>所以，next-key lock 即能保护该记录，又能阻止其他事务将新记录插入到被保护记录前面的间隙中。</p><p><strong>tips:</strong> next-key-lock是包含间隙锁和记录锁的，如果一个事务获取了X型的next-key lock，那么另一个事务在获取相同范围的X型next-key lock时，是会被阻塞的，就是因为存在记录锁，所以无法同时获取记录的更改权；</p><h2 id="mysql是怎么加行级锁的" tabindex="-1">MySQL是怎么加行级锁的？ <a class="header-anchor" href="#mysql是怎么加行级锁的" aria-label="Permalink to &quot;MySQL是怎么加行级锁的？&quot;">​</a></h2><p>加锁的对象是索引，加锁的基本单位是next-key lock；</p><p>next-key lock在一定程度上会退化成记录锁或者是间隙锁</p><ul><li>在能够使用记录所和间隙锁就能够避免幻读现象的场景下，next-key lock就会退化成记录锁或间隙锁</li></ul><h3 id="唯一索引等值查询" tabindex="-1">唯一索引等值查询 <a class="header-anchor" href="#唯一索引等值查询" aria-label="Permalink to &quot;唯一索引等值查询&quot;">​</a></h3><h4 id="记录存在的情况下" tabindex="-1">记录存在的情况下 <a class="header-anchor" href="#记录存在的情况下" aria-label="Permalink to &quot;记录存在的情况下&quot;">​</a></h4><p>可以通过</p><div class="language-sql vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">sql</span><pre class="shiki shiki-themes github-light github-dark vp-code"><code><span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> select</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> *</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> from</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> performance_schema</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">.</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">data_locks</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">\\G;</span></span></code></pre></div><img src="https://s2.loli.net/2024/04/16/yxbC9QqSPXRNpvU.png" alt="image-20240416140839377" style="zoom:80%;"><p>从上图可以看到，共加了两把锁，分别是:</p><ul><li>表锁：X类型的意向锁；</li><li>行锁：X类型的记录锁； <ul><li>如果LOCK_MODE是<strong>X</strong>，说明是<strong>next-key lock</strong></li><li>如果LOCK_MODE是<strong>X，REC_NOT_GAP</strong>，说明是记录锁；</li><li>如果LOCK_MODE是<strong>X，GAP</strong>，说明是<strong>间隙锁</strong>；</li></ul></li></ul><p><strong>加锁的对象针对的是索引</strong></p><blockquote><p>为什么上述情况下，唯一索引等值查询并且查询记录存在的情况下，该记录的索引中next-key lock会退化成记录锁？</p></blockquote><p>ans: 能够避免幻读现象</p><p>why: 幻读的定义是当一个事务前后两次查询的结果集，不相同就认为了发生了幻读，所以要避免幻读就是避免结果集某一条记录被其他事务删除，或者有其他事务插入了一条新的记录，这样前后两次查询的结果就会不一样。这次实验里只针对了id=1的记录，也就是结果集只有这一条记录，只要保证它不被删除或者被更新即可；</p><h4 id="记录不存在的情况下" tabindex="-1">记录不存在的情况下 <a class="header-anchor" href="#记录不存在的情况下" aria-label="Permalink to &quot;记录不存在的情况下&quot;">​</a></h4><div class="language-sql vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">sql</span><pre class="shiki shiki-themes github-light github-dark vp-code"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">mysql</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">&gt;</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> begin</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">;</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">Query OK, </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">0</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> rows</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> affected (</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">0</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">.</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">00</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> sec)</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">mysql</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">&gt;</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> select</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> *</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> from</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> user </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">where</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> id </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 2</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> for</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> update</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">;</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">Empty</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> set</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> (</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">0</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">.</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">03</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> sec)</span></span></code></pre></div><img src="https://s2.loli.net/2024/04/16/NtJi35avRpD4EWf.png" alt="image-20240416141939773" style="zoom:80%;"><p>从上图看，加了两个锁，分别是：</p><ul><li>表锁，X类型意向锁；</li><li>行锁，X类型间隙锁；</li></ul><p>因此，此时事务在id=5记录的主键索引上加的是间隙锁，锁住的范围是(1, 5)</p><p><img src="https://s2.loli.net/2024/04/16/wUFIic1MLln6obQ.png" alt="img"></p><p>接下来如果存在其他事务插入id值为2，3，4这一些记录的话，这些插入语句就会发生阻塞；为什么不是next-key lock呢？因为id=1和id=5的记录已经存在，通过主键唯一性就可以保证；</p><blockquote><p>可能会好奇，为什么能够确定(1, 5)是最终的间隙范围呢？</p></blockquote><p>如果LOCK_MODE是next-key或者间隙锁，那么LOCK_DATA就表示锁的范围[右边界]，此次事务A的LOCK_DATA就是5；</p><p>然后锁范围左边界是表中id=5的上一条记录的id值，即1，所以间隙锁的范围是(1, 5);</p><blockquote><p>为什么唯一索引等值查询并且查询记录「不存在」的场景下，在索引树找到第一条大于该查询记录的记录后，要将该记录的索引中的 next-key lock 会退化成「间隙锁」？</p></blockquote><p>总体来说，还是因为间隙锁就已经能够避免幻读问题？</p><p>从结果集上考虑，如果当前查id=2不存在，那么应该怎么做才能避免下次查询不会出现别的事务插入id=2的记录的情况</p><ul><li>在这个间隙范围内上一把锁，避免别的事务进行插入即可；</li><li>id=1 or id=5，通过主键唯一性即可避免插入；</li><li>无需给id=5上记录锁，因为当前查询是id=2的结果，删不删除id=5的记录对最后的结果影响不大；</li><li>为什么不可以针对不存在的记录加记录锁？因为锁是加在索引上的，这个场景下，查询的记录是不存在的，所以自然没办法锁住这条不存在的记录；</li></ul><h3 id="唯一索引范围查询" tabindex="-1">唯一索引范围查询 <a class="header-anchor" href="#唯一索引范围查询" aria-label="Permalink to &quot;唯一索引范围查询&quot;">​</a></h3>`,59),n=[e];function h(p,k,r,d,o,c){return i(),a("div",null,n)}const y=s(t,[["render",h]]);export{E as __pageData,y as default};
